 31	// GetBinding returns the persona bound to the specified role
 32	func (b *BindingManagerImpl) GetBinding(role string) (string, error) {
 33		if strings.TrimSpace(role) == "" {
 34			return "", NewPersonaError(ErrorValidation, "role cannot be empty", nil)
 35		}
 36	
 37		config, err := b.loadConfig()
 38		if err != nil {
 39			// Return the error so CLI can handle it
 40			return "", err
 41		}
 42	
 43		if config.Bindings == nil {
 44			return "", nil
 45		}
 46	
 47		persona, exists := config.Bindings[role]
 48		if !exists {
 49			return "", nil
 50		}
 51	
 52		return persona, nil
 53	}
 54	
 55	// SetBinding binds a persona to a role
 56	func (b *BindingManagerImpl) SetBinding(role, persona string) error {
 57		if strings.TrimSpace(role) == "" {
 58			return NewPersonaError(ErrorValidation, "role cannot be empty", nil)
 59		}
 60		if strings.TrimSpace(persona) == "" {
 61			return NewPersonaError(ErrorValidation, "persona cannot be empty", nil)
 62		}
 63	
 64		// Load existing config or create new one
 65		var config map[string]interface{}
 66	
 67		if fileExists(b.configPath) {
 68			content, err := os.ReadFile(b.configPath)
 69			if err != nil {
 70				return NewPersonaError(ErrorFileOperation,
 71					fmt.Sprintf("failed to read config file %s", b.configPath), err)
 72			}
 73	
 74			if err := yaml.Unmarshal(content, &config); err != nil {
 75				return NewPersonaError(ErrorInvalidConfig,
 76					fmt.Sprintf("failed to parse config file %s", b.configPath), err)
 77			}
 78		} else {
 79			config = make(map[string]interface{})
 80		}
 81	
 82		// Ensure persona_bindings section exists
 83		bindings, exists := config["persona_bindings"]
 84		if !exists {
 85			bindings = make(map[string]interface{})
 86			config["persona_bindings"] = bindings
 87		}
 88	
 89		// Convert to map if needed
 90		bindingsMap, ok := bindings.(map[string]interface{})
 91		if !ok {
 92			bindingsMap = make(map[string]interface{})
 93			config["persona_bindings"] = bindingsMap
 94		}
 95	
 96		// Set the binding
 97		bindingsMap[role] = persona
 98	
 99		// Save config
100		return b.saveConfig(config)
101	}
